19		use work.psi_tb_txt_util.all;
20		use work.top_tb_pkg.all;
21		use work.data_rec_register_pkg.all;
22	
23	------------------------------------------------------------------------------
24	-- Package Header
25	------------------------------------------------------------------------------
26	package top_tb_case2_pkg is
27	
28		constant CaseName_c : string := "Self Triggered Mode";
29	
30		procedure run(	signal ms		: out	axi_ms_r;
31						signal sm		: in	axi_sm_r;
32						signal aclk		: in	std_logic;
33						signal Clk 		: in 	std_logic;
34						signal ToDut	: out	In_t;
35						signal FromDut	: in	Out_t);
36						
37	end top_tb_case2_pkg;
38	
39	------------------------------------------------------------------------------
40	-- Package Body
41	------------------------------------------------------------------------------
42	package body top_tb_case2_pkg is
43	
44		procedure run(	signal ms		: out	axi_ms_r;
45						signal sm		: in	axi_sm_r;
46						signal aclk		: in	std_logic;
47						signal Clk 		: in 	std_logic;
48						signal ToDut	: out	In_t;
49						signal FromDut	: in	Out_t) is
50			constant SampleCount_c		: integer := 3;
51			constant PreTrigger_c		: integer := 1;
52			variable lastDoneCheck		: time;
53		begin
54			-- Print Message
55			print("Test: " & CaseName_c);
56			lastDoneCheck := now;
57			
58			-- Common configuration
59			axi_single_write(Reg_Totspl_Addr_c, SampleCount_c, ms, sm, aclk);
60			axi_single_write(Reg_Pretrig_Addr_c, PreTrigger_c, ms, sm, aclk);
61			axi_single_write(Reg_TrigEna_Addr_c, 1*2**Reg_TrigEna_SelfIdx_c, ms, sm, aclk);	
62			
63			-- Ch0 only, exit, no signedness
64			axi_single_write(Reg_SelftrigLo_Addr_c, -5, ms, sm, aclk);
65			axi_single_expect(Reg_SelftrigLo_Addr_c, -5, ms, sm, aclk, "Selftrig-Lo Readback Neg", 31, 0, true);
66			axi_single_write(Reg_SelftrigLo_Addr_c, 5, ms, sm, aclk);
67			axi_single_expect(Reg_SelftrigLo_Addr_c, 5, ms, sm, aclk, "Selftrig-Lo Readback Pos");
68			axi_single_write(Reg_SelftrigHi_Addr_c, -10, ms, sm, aclk);
69			axi_single_expect(Reg_SelftrigHi_Addr_c, -10, ms, sm, aclk, "Selftrig-Hi Readback Neg", 31, 0, true);
70			axi_single_write(Reg_SelftrigHi_Addr_c, 10, ms, sm, aclk);
71			axi_single_expect(Reg_SelftrigHi_Addr_c, 10, ms, sm, aclk, "Selftrig-Hi Readback Pos");
72			axi_single_write(Reg_SelftrigCfg_Addr_c, 1*2**0+2**Reg_SelftrigCfg_ExitSft_c, ms, sm, aclk);
73			axi_single_expect(Reg_SelftrigCfg_Addr_c, 1*2**0, ms, sm, aclk, "Selftrig-Cfg Readback - ENA", 7, 0);
74			axi_single_expect(Reg_SelftrigCfg_Addr_c, 1, ms, sm, aclk, "Selftrig-Cfg Readback - EXIT", Reg_SelftrigCfg_ExitSft_c, Reg_SelftrigCfg_ExitSft_c);
75			axi_single_expect(Reg_SelftrigCfg_Addr_c, 0, ms, sm, aclk, "Selftrig-Cfg Readback - ENTER", Reg_SelftrigCfg_EnterSft_c, Reg_SelftrigCfg_EnterSft_c);
76			axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
77			wait for 300 ns;
78			assert FromDut.Done_Irq = '0' and FromDut.Done_Irq'last_event > now - lastDoneCheck report "Done_Irq was high after arming" severity error;			-- done is only checked on first self-trigger
79			lastDoneCheck := now;
80			InputSamplesNoCh(MemoryDepth_v*2, ToDut, Clk, 0, 1, 1);
81			wait for 100 ns;	
82			assert FromDut.Done_Irq'last_event < now - lastDoneCheck report "Done_Irq was low after recording" severity error;			-- done is only checked on first self-trigger
83			lastDoneCheck := now;
84			axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
85			CheckDataNoCh(SampleCount_c, 10, 1, 1, ms, sm, aclk);
86			
87			-- ch2 only, exit, no signedness
